import XCTest
@testable import SplitThin

final class BitmapVerificationTest: XCTestCase {

    let decoder = DefaultPayloadDecoder()

    func testExample1AllMatchingKeysAreInBitmap() throws {
        let keys = [
            "Rafael", "Sergio",
            "Teresa", "Messi", "PA",
            "Pato", "HenryTheKing", "Fernandito", "Kayle", "Adil"
        ]

        let example1Payload = ""

        let keyMap = try decoder.decodeAsBytes(payload: example1Payload, compressionType: .zlib)

        var missing: [String] = []
        for key in keys where !decoder.isKeyInBitmap(keyMap: keyMap, hashedKey: decoder.hashKey(key)) {
            missing.append(key)
        }

        XCTAssertTrue(missing.isEmpty, "These matchingKeys are NOT in the bitmap: \(missing)")
    }

    func testExample1AllMatchingKeysAreInBitmap2() throws {
        let keys = [
            "Emma", "Gaston", "Rafael", "Ricardo", "Sergio",
            "martin", "Martin", "Teresa", "Messi", "PA",
            "Pato", "HenryTheKing", "Fernandito", "Kayle", "Adil"
        ]

        let example1Payload = ""

        let keyMap = try decoder.decodeAsBytes(payload: example1Payload, compressionType: .zlib)

        var missing: [String] = []
        for key in keys where !decoder.isKeyInBitmap(keyMap: keyMap, hashedKey: decoder.hashKey(key)) {
            missing.append(key)
        }

        XCTAssertTrue(missing.isEmpty, "These matchingKeys are NOT in the bitmap: \(missing)")
    }
}
